   137→	}
   138→
   139→	// Done!
   140→	return &routeRegexp{
   141→		template:         template,
   142→		regexpType:       typ,
   143→		options:          options,
   144→		regexp:           reg,
   145→		reverse:          reverse.String(),
   146→		varsN:            varsN,
   147→		varsR:            varsR,
